const { GSDKnowledgeSync } = require('./index.js');
const sync = new GSDKnowledgeSync();

// Comprehensive test suite for T04: Full file path in embedding
let passed = 0, failed = 0;

function assert(condition, msg) {
  if (condition) { console.log('✅ ' + msg); passed++; } 
  else { console.error('❌ FAIL: ' + msg); failed++; }
}

// Test 1: Path is first line for normal payload
const p1 = { signatures:['function foo() {}'], exports:['foo'], imports:['./bar'], symbolNames:['foo'], comments:[], language:'javascript', kindDetail:'code' };
const r1 = sync.buildCodeText('src/hooks/post-commit.sh', '', p1);
assert(r1.split('\n')[0] === 'src/hooks/post-commit.sh', 'T1: Path is first line');

// Test 2: No 'path:' prefix anywhere in output
assert(!r1.includes('path:'), 'T2: No \"path:\" prefix');

// Test 3: Full path preserved (not truncated)
assert(r1.includes('src/hooks/post-commit.sh'), 'T3: Full path present');

// Test 4: Path first even with empty payload
const p2 = { signatures:[], exports:[], imports:[], symbolNames:[], comments:[], language:'javascript', kindDetail:'code' };
const r2 = sync.buildCodeText('index.js', '', p2);
assert(r2.split('\n')[0] === 'index.js', 'T4: Path first with empty payload');

// Test 5: Nested path works
const r3 = sync.buildCodeText('packages/core/src/utils/helpers.ts', '', { ...p1 });
assert(r3.split('\n')[0] === 'packages/core/src/utils/helpers.ts', 'T5: Nested path preserved');

// Test 6: Backward compatibility — all metadata still present
const lines = r1.split('\n').filter(Boolean);
assert(lines.some(l => l.startsWith('project:')), 'T6: project: field present');
assert(lines.some(l => l.startsWith('language:')), 'T7: language: field present');
assert(lines.some(l => l.startsWith('kind:')), 'T8: kind: field present');

// Test 7: Syntax check of modified file
const fs = require('fs');
try { new Function(fs.readFileSync('./index.js', 'utf8')); console.log('✅ T9: index.js syntax valid (function eval)'); passed++; } 
catch(e) { console.error('❌ T9: index.js has syntax error:', e.message); failed++; }

console.log('\n' + '='.repeat(50));
console.log(\`Results: \${passed} passed, \${failed} failed\`);
process.exit(failed > 0 ? 1 : 0);
